#@help _openvpn_disconnect1
# @internal disconnect chain step (emits the disconnect commands)
#@end
_openvpn_disconnect1() {
  local interface="$1"

  # Find session by interface name
  local session_pid=$(find_session_by_interface "$interface")

  if [ -z "$session_pid" ]; then
    generate_error "No vpn-switch session found for interface: $interface"
    return 0
  fi

  local session_dir="$VPN_SWITCH_BASE/.session/$session_pid"
  local disconnect_script="$session_dir/disconnect.sh"

  # Build VPN_SWITCH_CONTEXT_DISCONNECT (new context variable system)
  VPN_SWITCH_CONTEXT_DISCONNECT="
export VPN_SESSION_DIR='$session_dir'
export VPN_SESSION_PID='$session_pid'
export VPN_INTERFACE='$interface'
export VPN_PROTOCOL='openvpn'
"
  export VPN_SWITCH_CONTEXT_DISCONNECT

  # If disconnect.sh exists (phase-based sessions), use it
  if [ -f "$disconnect_script" ]; then
    cat "$disconnect_script"
  else
    # Legacy fallback for old sessions created before phase-based implementation
    local original_config=$(cat "$session_dir/original" 2>>"$LOG_FILE" || echo "unknown")
    local original_config_relative="${original_config#$VPN_SWITCH_BASE/}"
    original_config_relative="../../$original_config_relative"

    local pfctl="${VPN_SWITCH_PFCTL:-pfctl}"
    local vpn_dns_table="${VPN_SWITCH_VPN_DNS_TABLE:-vpn_dns}"
    local vpn_remotes_table="${VPN_SWITCH_VPN_REMOTES_TABLE:-vpn_remotes}"

    # Generate legacy cleanup commands
    cat <<EOF
# Disconnect OpenVPN interface: $interface (legacy mode - no disconnect.sh found)
# Session PID: $session_pid
# Original config: $original_config_relative

# Kill OpenVPN daemon process
if [ -f "$session_dir/openvpn.pid" ]; then
  openvpn_pid=\$(cat "$session_dir/openvpn.pid" 2>>"$LOG_FILE")
  if [ -n "\$openvpn_pid" ]; then
    echo "# Killing OpenVPN daemon (PID: \$openvpn_pid)..."
    kill -TERM "\$openvpn_pid" 2>>"$LOG_FILE" || true
    sleep 1
  fi
fi

# Destroy interface
echo "# Cleaning up interface: $interface"
$(printf "$MODIFY_INTERFACE_DESTROY_FMT" "$interface") 2>>"$LOG_FILE" || true

# Clean up firewall tables
echo "# Cleaning up firewall tables..."
$pfctl -t "$vpn_dns_table" -T flush 2>>"$LOG_FILE" || true
$pfctl -t "$vpn_remotes_table" -T flush 2>>"$LOG_FILE" || true

echo "# VPN disconnected: $interface"
echo "# Note: Session metadata will be cleaned up by 'session stop'"
EOF
  fi
}

#@help _openvpn_patch1
# @command openvpn patch <config>
# @summary Preview the patched config that would be used to connect
# @group   openvpn
# @param   config  config to preview
# @returns the patched configuration
# @example vpn-switch openvpn patch us-server.ovpn
#@end
_openvpn_patch1() {
  local config_name="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Resolve config path (handle both relative and absolute paths)
  local config_path=""
  case "$config_name" in
    /*)
      # Absolute path - use as-is
      config_path="$config_name"
      ;;
    *)
      # Relative path - resolve from openvpn directory
      config_path="$ovpn_dir/$config_name"
      ;;
  esac

  # Validate config exists
  if [ ! -f "$config_path" ]; then
    generate_error "Config file not found: $config_path"
    return 0
  fi

  # Validate it's readable
  if [ ! -r "$config_path" ]; then
    generate_error "Config file not readable: $config_path"
    return 0
  fi

  # Output patched config to stdout using patch_openvpn_config helper
  # Note: /dev/stdout is POSIX-compliant for output redirection
  patch_openvpn_config "$config_path" /dev/stdout
}

