#@help _openvpn_enumerate0
# @internal OpenVPN enumeration helper
#@end
_openvpn_enumerate0() {
  # Process Table Analysis - enumerate running OpenVPN processes
  # Generates shell code that examines process table at execution time

  cat <<EOF
ps_output=\$(ps auxww 2>>"$LOG_FILE" | grep '[o]penvpn' || true)

if [ -z "\$ps_output" ]; then
  echo "# No openvpn processes found"
  exit 0
fi

echo "\$ps_output" | while IFS= read -r line; do
  pid=\$(echo "\$line" | awk '{print \$2}')
  cmd=\$(echo "\$line" | awk '{for(i=11;i<=NF;i++) printf \$i " "; print ""}')
  config=\$(echo "\$cmd" | sed -n 's/.*--config[[:space:]]*\([^[:space:]]*\).*/\1/p')

  if [ -z "\$config" ]; then
    config='(inline configuration)'
  fi

  if echo "\$config" | grep -q "^$VPN_SWITCH_BASE/.session/"; then
    session_id=\$(echo "\$config" | sed "s|^$VPN_SWITCH_BASE/.session/\([^/]*\)/.*|\1|")
    echo "#"
    echo "# ✓ openvpn (PID \$pid) [managed by this instance]"
    echo "#   Config: \$config"
    echo "#   Session: \$session_id"
  elif echo "\$config" | grep -q '/.session/'; then
    other_base=\$(echo "\$config" | sed 's|\(.*\)/.session/.*|\1|')
    echo "#"
    echo "# ⚠ openvpn (PID \$pid) [different vpn-switch instance]"
    echo "#   Config: \$config"
    echo "#   Instance: \$other_base"
  else
    echo "#"
    echo "# ⚠ openvpn (PID \$pid) [NOT managed by vpn-switch]"
    echo "#   Config: \$config"
  fi
done
EOF
}

#@help _openvpn_import1
# @command openvpn import <path>
# @summary Import an OpenVPN .ovpn file into the database
# @group   openvpn
# @param   path  path to a .ovpn file to import
# @returns shell commands (copy config into the database)
# @example vpn-switch openvpn import ~/vpn/us-server.ovpn
# @see     openvpn list
#@end
_openvpn_import1() {
  local source_path="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Validate source file
  if [ ! -f "$source_path" ]; then
    generate_error "File not found: $source_path"
    return 0
  fi

  # Extract filename
  local filename=$(basename -- "$source_path")

  # Validate file extension
  case "$filename" in
    *.ovpn) ;;
    *)
      generate_error "Not an OpenVPN config - must end in .ovpn: $filename"
      return 0
      ;;
  esac

  local dest_path="$ovpn_dir/$filename"

  # Check if already exists
  if [ -e "$dest_path" ]; then
    generate_error "Config already exists: openvpn/$filename"
    return 0
  fi

  # Output commands to copy file
  cat <<EOF
# Import OpenVPN config: $filename
$MODIFY_FILE_COPY "$source_path" "$dest_path"
$MODIFY_FILE_PERMS 0400 "$dest_path"
echo "# Imported: openvpn/$filename" >&2
EOF
}

