  local group="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"

  # Validate group exists
  if [ ! -d "$group_dir" ]; then
    generate_error "Group not found: $group"
    return 0
  fi

  echo "# Group: $group"

  # Iterate over all items in group directory
  for item in "$group_dir"/*; do
    # Skip if no items found
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    local item_name=$(basename -- "$item")

    # Show symlink target if it's a link
    if [ -L "$item" ]; then
      local target=$(readlink "$item")
      echo "openvpn/$group/$item_name -> $target"
    else
      # Regular file/directory (shouldn't happen in groups, but be safe)
      echo "openvpn/$group/$item_name"
    fi
  done | sort
}

#@help _openvpn_add1
# @command openvpn add <group> [<config> [<alias>]]
# @summary Create a group, or link a config into one
# @group   openvpn
# @param   group   group to create or add to
# @param   config  config to link into the group
# @param   alias   custom link name (default: derived)
# @returns shell commands (create group / create symlink)
# @example vpn-switch openvpn add work us-server.ovpn office
# @see     openvpn link
#@end
_openvpn_add1() {
  local group="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"

  # Validate group name (no slashes, dots, etc)
  case "$group" in
    */*|*.*|*.*)
      generate_error "Invalid group name - no slashes or dots allowed: $group"
      return 0
      ;;
  esac

  # Check if already exists
  if [ -e "$group_dir" ]; then
    generate_error "Group already exists: $group"
    return 0
  fi

  # Output commands to create directory
  cat <<EOF
# Create group: $group
$MODIFY_DIR_CREATE "$group_dir"
$MODIFY_FILE_PERMS 0700 "$group_dir"
echo "# Created group: openvpn/$group/" >&2
EOF
}

#@help __openvpn_add2
# @internal arity-2 sibling of 'openvpn add' (config into group)
#@end
__openvpn_add2() {
  local group="$1"
  local target="$2"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"
  local target_path="$ovpn_dir/$target"

  # Validate group exists
  if [ ! -d "$group_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Group not found: $group\""
    return
  fi

  # Validate target exists
  if [ ! -f "$target_path" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Config not found: openvpn/$target\""
    return
  fi

  # Derive link name from target (remove .ovpn extension)
  local alias=$(basename -- "$target" .ovpn)
  local link_path="$group_dir/$alias"

  # Check if link already exists
  if [ -e "$link_path" ] || [ -L "$link_path" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Alias already exists in group $group: $alias\""
    return
  fi

  # Delegate to add3 with derived alias
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn add \"$group\" \"$target\" \"$alias\""
}

#@help _openvpn_add3
# @internal arity-3 sibling of 'openvpn add' (config + custom alias)
#@end
_openvpn_add3() {
  local group="$1"
  local target="$2"
  local alias="$3"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"
  local target_path="$ovpn_dir/$target"
  local link_path="$group_dir/$alias"

  # Validate group exists
  if [ ! -d "$group_dir" ]; then
    generate_error "Group not found: $group"
    display plain "Use: openvpn add $group"
    return 0
  fi

  # Validate target exists
  if [ ! -f "$target_path" ]; then
    generate_error "Config not found: openvpn/$target"
    return 0
  fi

  # Validate alias doesn't contain slashes
  case "$alias" in
    */*)
      generate_error "Invalid alias - no slashes allowed: $alias"
      return 0
      ;;
  esac

  # Check if link already exists
  if [ -e "$link_path" ] || [ -L "$link_path" ]; then
    generate_error "Alias already exists in group $group: $alias"
    return 0
  fi

  # Output commands to create symlink (relative path)
  cat <<EOF
# Add link to group: openvpn/$group/$alias -> $target
$MODIFY_LINK_CREATE "../$target" "$group_dir/$alias"
echo "# Added to group $group: $alias -> $target" >&2
EOF
}

#@help _openvpn_link2
# @command openvpn link <alias> <target>
# @summary Create a protocol-level alias to a config
# @group   openvpn
# @param   alias   new alias name
# @param   target  config the alias points to
# @returns shell commands (create symlink)
# @example vpn-switch openvpn link quick us-server.ovpn
# @see     openvpn add
#@end
_openvpn_link2() {
  local alias="$1"
  local target="$2"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local alias_path="$ovpn_dir/$alias"
  local target_path="$ovpn_dir/$target"

  # Validate target exists
  if [ ! -f "$target_path" ]; then
    generate_error "Config not found: openvpn/$target"
    return 0
  fi

  # Check if alias already exists
  if [ -e "$alias_path" ] || [ -L "$alias_path" ]; then
    generate_error "Alias already exists: $alias"
    return 0
  fi

  # Output commands to create symlink (relative path for same directory)
  cat <<EOF
# Create link in openvpn/: $alias -> $target
$MODIFY_LINK_CREATE "./$target" "$alias_path"
echo "# Created link: openvpn/$alias -> $target" >&2
EOF
}

#@help _openvpn_remove1
# @command openvpn remove <name>
# @summary Remove a config or link (with safety checks)
# @group   openvpn
# @param   name  config or link to remove
# @returns shell commands (remove the target)
# @example vpn-switch openvpn remove old-server
#@end
_openvpn_remove1() {
  local name="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local target_path="$ovpn_dir/$name"

  # Validate exists
  if [ ! -e "$target_path" ] && [ ! -L "$target_path" ]; then
    generate_error "Not found: openvpn/$name"
    return 0
  fi

  # If it's a directory (group), refuse
  if [ -d "$target_path" ]; then
    generate_error "Cannot remove group this way"
    display plain "Use: openvpn remove <group> <link>"
    return 0
  fi

  # Check if referenced by any group symlinks
  for group_dir in "$ovpn_dir"/*/; do
    [ ! -d "$group_dir" ] && continue

    for link in "$group_dir"/*; do
      [ ! -L "$link" ] && continue
      local target=$(readlink "$link")
      # Normalize paths for comparison
      local target_basename=$(basename -- "$target")
      if [ "$target_basename" = "$name" ] || [ "$target" = "../$name" ]; then
        local group=$(basename -- "$group_dir")
        generate_error "Config referenced by group link: $group/$(basename -- "$link") -> $name"
        return 0
      fi
    done
  done

  # Output commands to remove
  cat <<EOF
# Remove: openvpn/$name
$MODIFY_FILE_REMOVE "$target_path"
echo "# Removed: openvpn/$name" >&2
EOF
}

#@help _openvpn_remove2
# @internal arity-2 variant of 'openvpn remove' (remove link from a group)
#@end
_openvpn_remove2() {
  local group="$1"
  local link="$2"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"
  local link_path="$group_dir/$link"

  # Validate group exists
  if [ ! -d "$group_dir" ]; then
    generate_error "Group not found: $group"
    return 1
  fi

  # Validate link exists
  if [ ! -L "$link_path" ]; then
    generate_error "Link not found: openvpn/$group/$link"
    return 1
  fi

  # Output commands to remove
  cat <<EOF
# Remove group link: openvpn/$group/$link
$MODIFY_FILE_REMOVE "$link_path"
echo "# Removed: openvpn/$group/$link" >&2
EOF
}

#@help _openvpn_validate0
# @command openvpn validate
# @summary Check OpenVPN symlink integrity in the database
# @group   openvpn
# @returns validation report
# @example vpn-switch openvpn validate
# @see     openvpn clean
#@end
_openvpn_validate0() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local has_errors=0
  local has_warnings=0

  # Check if openvpn directory exists
  if [ ! -d "$ovpn_dir" ]; then
    echo "# [ERROR] OpenVPN directory not found: $ovpn_dir"
    return 1
  fi

  echo "# === OpenVPN Configuration Validation ==="
  echo "#"

  # Check for broken symlinks in protocol directory
  echo "# Checking protocol directory for broken symlinks..."
  for item in "$ovpn_dir"/*; do
    # Skip if no items
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Check if symlink and broken
    if [ -L "$item" ] && [ ! -e "$item" ]; then
      local item_name=$(basename -- "$item")
      echo "# [ERROR] Broken symlink: openvpn/$item_name"
      has_errors=1
    fi
  done

  # Check for broken symlinks in groups
  echo "#"
  echo "# Checking groups for broken symlinks..."
  for group_dir in "$ovpn_dir"/*/; do
    [ ! -d "$group_dir" ] && continue
    local group=$(basename -- "$group_dir")

    for item in "$group_dir"/*; do
      # Skip if no items
      [ ! -e "$item" ] && [ ! -L "$item" ] && continue

      # Check if symlink and broken
      if [ -L "$item" ] && [ ! -e "$item" ]; then
        local item_name=$(basename -- "$item")
        echo "# [ERROR] Broken symlink: $group/$item_name"
        has_errors=1
      fi
    done
  done

  # Check for naming conflicts (file and directory with same name)
  echo "#"
  echo "# Checking for naming conflicts..."
  for item in "$ovpn_dir"/*; do
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    local base_name=$(basename -- "$item")

    # Skip directories and non-ovpn files for this check
    [ -d "$item" ] && continue
    [ ! -f "$item" ] && [ ! -L "$item" ] && continue

    # Check if there's also a directory with the same name (without .ovpn)
    local name_without_ext="${base_name%.ovpn}"
    if [ -d "$ovpn_dir/$name_without_ext" ]; then
      echo "# [WARNING] Naming conflict: openvpn/$base_name (file) and openvpn/$name_without_ext/ (directory)"
      has_warnings=1
    fi
  done

  # Check for basic config file validity (just check if readable and non-empty)
  echo "#"
  echo "# Checking config file validity..."
  for item in "$ovpn_dir"/*.ovpn; do
    # Skip if glob didn't match any files
    [ ! -e "$item" ] && continue

    local config_name=$(basename -- "$item")

    # Check if readable
    if [ ! -r "$item" ]; then
      echo "# [ERROR] Config not readable: openvpn/$config_name"
      has_errors=1
      continue
    fi

    # Check if non-empty
    if [ ! -s "$item" ]; then
      echo "# [WARNING] Config file is empty: openvpn/$config_name"
      has_warnings=1
      continue
    fi

    # Check for basic OpenVPN directives (client or remote). Use ERE: BRE '\|'
    # alternation is a GNU/FreeBSD extension that OpenBSD grep does not accept,
    # so '^\(client\|remote\)' matched nothing there and flagged valid configs.
    if ! grep -qE "^(client|remote)" "$item" 2>>"$LOG_FILE"; then
      echo "# [WARNING] Config missing OpenVPN directives (client/remote): openvpn/$config_name"
      has_warnings=1
    fi
  done

  # Summary
  echo "#"
  if [ $has_errors -eq 0 ] && [ $has_warnings -eq 0 ]; then
    echo "# Validation complete: No issues found"
    return 0
  elif [ $has_errors -eq 0 ]; then
    echo "# Validation complete: Warnings found (no errors)"
    return 0
  else
    echo "# Validation complete: Errors found"
    return 1
  fi
}

#@help ___openvpn_clean0
# @command openvpn clean
# @summary Generate cleanup commands for broken links
# @group   openvpn
# @returns shell commands (review, then pipe to sh)
# @example vpn-switch openvpn clean | sh
# @see     openvpn validate
#@end
___openvpn_clean0() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  echo "# OpenVPN database cleanup commands"
  echo "# Pipe to sh to execute: vpn-switch openvpn clean | sh"
  echo ""

  # Check protocol-level links
  for item in "$ovpn_dir"/*; do
    [ ! -L "$item" ] && continue
    [ -e "$item" ] && continue  # Skip if target exists

    local item_name=$(basename -- "$item")
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn remove \"$item_name\""
  done

  # Check group links
  for group_dir in "$ovpn_dir"/*/; do
    [ ! -d "$group_dir" ] && continue
    local group=$(basename -- "$group_dir")

    for link in "$group_dir"/*; do
      [ ! -L "$link" ] && continue
      [ -e "$link" ] && continue  # Skip if target exists

      local link_name=$(basename -- "$link")
      echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn remove \"$group\" \"$link_name\""
    done
  done
}

#@help _openvpn_info1
# @command openvpn info <group>
# @summary Show group details and configurations
# @group   openvpn
# @param   group  group to inspect
# @returns group report
# @example vpn-switch openvpn info work
#@end
_openvpn_info1() {
  local group="$1"
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"
  local group_dir="$ovpn_dir/$group"

  # Validate group exists
  if [ ! -d "$group_dir" ]; then
    generate_error "Group not found: $group"
    return 1
  fi

  echo "# Group: $group"
  echo "# Path: $group_dir"
  echo ""

  # Count items
  local total=0
  for item in "$group_dir"/*; do
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue
    total=$((total + 1))
  done

  echo "# Total links: $total"
  echo ""
  echo "# Contents:"

  # List with targets
  for entry in "$group_dir"/*; do
    [ ! -e "$entry" ] && [ ! -L "$entry" ] && continue

    local basename_entry=$(basename -- "$entry")

    if [ -L "$entry" ]; then
      # Symlink - show target
      local target=$(readlink "$entry")
      echo "#   $basename_entry -> $target"
    elif [ -f "$entry" ]; then
      # Regular file
      echo "#   $basename_entry"
    fi
  done | sort
}

#@help ___openvpn_dump0
# @command openvpn dump
# @summary Generate restorable shell commands for all OpenVPN configs
# @group   openvpn
# @returns shell commands (restorable database dump)
# @example vpn-switch openvpn dump
# @see     dump
#@end
___openvpn_dump0() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Validate openvpn directory exists
  if [ ! -d "$ovpn_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"OpenVPN directory not found: $ovpn_dir\""
    return 0
  fi

  # Phase 1: Import all configs (absolute paths from SOURCE database)
  echo "# Import openvpn configurations"
  for config_file in "$ovpn_dir"/*.ovpn; do
    [ ! -f "$config_file" ] && continue

    # Skip files with newlines in name (cannot be safely represented in line-based dump)
    if has_newline_in_path "$config_file"; then
      echo "# WARNING: Skipping file with newline in name (cannot be safely dumped)"
      continue
    fi

    # Use absolute path for imports with proper quoting
    # Output literal \$VPN_SWITCH_CONTEXT_SCRIPT so it expands during restore
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn import \"$config_file\""
  done

  # Output separator
  echo ""

  # Phase 2: Create groups
  echo "# Create groups"
  scan_openvpn_groups | while IFS= read -r group_path; do
    # Extract group name (remove openvpn/ prefix and / suffix)
    local group=$(echo "$group_path" | sed 's|^openvpn/||' | sed 's|/$||')
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn add $group"
  done

  # Output separator
  echo ""

  # Phase 3: Create protocol-level links (aliases in openvpn/ directory)
  echo "# Create protocol-level links"
  scan_openvpn_links | while IFS= read -r link_info; do
    # Parse "openvpn/alias -> target" format
    local alias=$(echo "$link_info" | sed 's|^openvpn/||' | sed 's| ->.*||')
    local target=$(echo "$link_info" | sed 's|.* -> ||')
    # Normalize target: strip ./ prefix (openvpn link will add it back)
    target=$(echo "$target" | sed 's|^\./||')
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn link $alias $target"
  done

  # Output separator
  echo ""

  # Phase 4: Create group links
  echo "# Create group links"
  scan_openvpn_groups | while IFS= read -r group_path; do
    # Extract group name
    local group=$(echo "$group_path" | sed 's|^openvpn/||' | sed 's|/$||')
    local group_dir="$ovpn_dir/$group"

    # Scan for links in this group
    for link_file in "$group_dir"/*; do
      [ ! -L "$link_file" ] && continue
      local link_name=$(basename -- "$link_file")
      local target=$(readlink "$link_file")
      local target_basename=$(basename -- "$target")

      # Determine if this is arity-2 (link and target have same name) or arity-3 (different)
      local target_base=$(basename -- "$target" .ovpn)
      if [ "$link_name" = "$target_base" ] || [ "$link_name" = "$target_basename" ]; then
        # Arity-2: same name
        echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn add $group $target_basename"
      else
        # Arity-3: custom name
        echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn add $group $target_basename $link_name"
      fi
    done
  done
}

#@help __openvpn_help0
# @command openvpn help
# @summary Show OpenVPN command help
# @group   openvpn
# @returns help text
# @example vpn-switch openvpn help
#@end
__openvpn_help0() {
  # Backward compatibility: delegate to new pattern "help openvpn"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" help openvpn"
}

patch_openvpn_config() {
  local source_config="$1"
  local dest_config="$2"
  local resolvconf_base="${VPN_SWITCH_RESOLVCONF_openvpn:-/usr/local/sbin/ovpn-resolvconf}"
  local interface="${VPN_SWITCH_INTERFACE_openvpn:-tun0}"
  local credentials_file="${VPN_SWITCH_CREDENTIALS_openvpn:-}"

  # Derive session directory from destination path (for PID file)
  local session_dir
  if [ "$dest_config" = "/dev/stdout" ]; then
    # When outputting to stdout, use a placeholder for PID file
    session_dir="SESSION_DIR"
  else
    session_dir=$(dirname "$dest_config")
  fi
  local pid_file="$session_dir/openvpn.pid"

  # Use awk to patch config (supports stdout, no temp files needed)
  awk -v resolvconf_up="${resolvconf_base}-up" \
      -v resolvconf_down="${resolvconf_base}-down" \
      -v iface="$interface" \
      -v pidfile="$pid_file" \
      -v credentials_file="$credentials_file" '
    BEGIN {
      has_dev=0
      has_daemon=0
      has_writepid=0
      # Phase-based approach: up/down not tracked (stripped from config)
      # has_up=0
      # has_down=0
    }

    # Phase-based approach: Strip any existing up/down scripts
    # DNS configuration is handled entirely by the DNS phase, not OpenVPN up/down scripts
    # This prevents OpenVPN from exiting if up script fails (e.g., no DNS push from server)
    /^up / || /^down / {
      next  # Skip these lines entirely
    }

    # Update existing dev directive
    /^dev / {
      print "dev " iface
      has_dev=1
      next
    }

    # Mark daemon as present (update or keep)
    /^daemon/ {
      has_daemon=1
      print
      next
    }

    # Update existing writepid directive
    /^writepid / {
      print "writepid " pidfile
      has_writepid=1
      next
    }

    # Patch bare auth-user-pass directive (interactive prompt) with credentials file
    # Only patch if VPN_SWITCH_CREDENTIALS_openvpn is set
    /^auth-user-pass$/ {
      if (credentials_file != "") {
        print "auth-user-pass " credentials_file
      } else {
        print  # Leave unchanged for interactive prompt
      }
      next
    }

    # Leave auth-user-pass with existing path unchanged
    /^auth-user-pass / {
      print
      next
    }

    # Pass through all other lines
    { print }

    # Add missing directives at end
    END {
      if (!has_dev) print "dev " iface
      if (!has_daemon) print "daemon"
      if (!has_writepid) print "writepid " pidfile
      # Phase-based approach: DNS handled by phase scripts, not OpenVPN up/down
      # if (!has_up) print "up " resolvconf_up
      # if (!has_down) print "down " resolvconf_down
    }
  ' "$source_config" > "$dest_config"

  # Set permissions (skip if outputting to stdout)
  if [ "$dest_config" != "/dev/stdout" ]; then
    $MODIFY_FILE_PERMS 0400 "$dest_config"
  fi
}

get_openvpn_remotes() {
  local config_file="$1"

  # Extract IP addresses from "remote <ip> <port>" lines
  awk '/^remote / { print $2 }' "$config_file"
}

scan_openvpn_links() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Find all symlinks that are NOT config files (i.e., protocol-level aliases)
  for item in "$ovpn_dir"/*; do
    # Skip if no items found
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip directories (groups)
    [ -d "$item" ] && continue

    # Skip if not a symlink
    [ ! -L "$item" ] && continue

    local item_name=$(basename -- "$item")

    # Skip .ovpn files (those are listed in configs section)
    case "$item_name" in
      *.ovpn) continue ;;
    esac

    # Show symlink with target
    local target=$(readlink "$item")
    echo "openvpn/$item_name -> $target"
  done | sort
}

scan_openvpn_groups() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Find all subdirectories, add hierarchy prefix and "/" suffix
  # Use find -H to follow symlinks on command line (for $ovpn_dir) but not inside
  find -H "$ovpn_dir" -maxdepth 1 -type d ! -path "$ovpn_dir" -exec basename {} \; 2>>"$LOG_FILE" | \
    sed 's|^|openvpn/|' | \
    sed 's|$|/|' | \
    sort
}

scan_openvpn_configs() {
  local ovpn_dir="$VPN_SWITCH_BASE/openvpn"

  # Find all .ovpn files (both regular files and symlinks ending in .ovpn)
  # Use find -H to follow symlinks on command line (for $ovpn_dir) but not inside
  find -H "$ovpn_dir" -maxdepth 1 \( -type f -o -type l \) -name "*.ovpn" -exec basename {} \; 2>>"$LOG_FILE" | \
    sed 's|^|openvpn/|' | \
    sort
}

scan_group_links() {
  local group="$1"
  local group_dir="$VPN_SWITCH_BASE/openvpn/$group"

  # Find all items in group, add hierarchy prefix
  # Note: Groups contain symlinks, not actual files
  find -H "$group_dir" -maxdepth 1 -type l -exec basename {} \; 2>>"$LOG_FILE" | \
    sed "s|^|openvpn/$group/|" | \
    sort
}

